1	import { resolveDefaultAgentId } from "../agents/agent-scope.js";
2	import type { ChatType } from "../channels/chat-type.js";
3	import { normalizeChatType } from "../channels/chat-type.js";
4	import type { OpenClawConfig } from "../config/types.openclaw.js";
5	import { shouldLogVerbose } from "../globals.js";
6	import { logDebug } from "../logger.js";
7	import { normalizeLowercaseStringOrEmpty } from "../shared/string-coerce.js";
8	import { listBindings } from "./bindings.js";
9	import {
10	  buildAgentMainSessionKey,
11	  buildAgentPeerSessionKey,
12	  DEFAULT_ACCOUNT_ID,
