27	export type ResolveAgentRouteInput = {
28	  cfg: OpenClawConfig;
29	  channel: string;
30	  accountId?: string | null;
31	  peer?: RoutePeer | null;
32	  /** Parent peer for threads — used for binding inheritance when peer doesn't match directly. */
33	  parentPeer?: RoutePeer | null;
34	  guildId?: string | null;
35	  teamId?: string | null;
36	  /** Discord member role IDs — used for role-based agent routing. */
37	  memberRoleIds?: string[];
38	};
