40	export type ResolvedAgentRoute = {
41	  agentId: string;
42	  channel: string;
43	  accountId: string;
44	  /** Internal session key used for persistence + concurrency. */
45	  sessionKey: string;
46	  /** Convenience alias for direct-chat collapse. */
47	  mainSessionKey: string;
48	  /** Which session should receive inbound last-route updates. */
49	  lastRoutePolicy: "main" | "session";
50	  /** Match description for debugging/logging. */
51	  matchedBy:
52	    | "binding.peer"
53	    | "binding.peer.parent"
54	    | "binding.peer.wildcard"
55	    | "binding.guild+roles"
56	    | "binding.guild"
57	    | "binding.team"
58	    | "binding.account"
59	    | "binding.channel"
60	    | "default";
61	};
