63	export { DEFAULT_ACCOUNT_ID, DEFAULT_AGENT_ID } from "./session-key.js";
64	
65	export function deriveLastRoutePolicy(params: {
66	  sessionKey: string;
67	  mainSessionKey: string;
68	}): ResolvedAgentRoute["lastRoutePolicy"] {
69	  return params.sessionKey === params.mainSessionKey ? "main" : "session";
70	}
71	
72	export function resolveInboundLastRouteSessionKey(params: {
73	  route: Pick<ResolvedAgentRoute, "lastRoutePolicy" | "mainSessionKey">;
74	  sessionKey: string;
75	}): string {
76	  return params.route.lastRoutePolicy === "main" ? params.route.mainSessionKey : params.sessionKey;
77	}
78	
79	function normalizeToken(value: string | undefined | null): string {
80	  return normalizeLowercaseStringOrEmpty(value);
81	}
82	
83	function normalizeId(value: unknown): string {
84	  if (typeof value === "string") {
85	    return value.trim();
86	  }
87	  if (typeof value === "number" || typeof value === "bigint") {
88	    return String(value).trim();
89	  }
90	  return "";
91	}
