93	export function buildAgentSessionKey(params: {
94	  agentId: string;
95	  channel: string;
96	  accountId?: string | null;
97	  peer?: RoutePeer | null;
98	  /** DM session scope. */
99	  dmScope?: "main" | "per-peer" | "per-channel-peer" | "per-account-channel-peer";
100	  identityLinks?: Record<string, string[]>;
101	}): string {
102	  const channel = normalizeToken(params.channel) || "unknown";
103	  const peer = params.peer;
104	  return buildAgentPeerSessionKey({
105	    agentId: params.agentId,
106	    mainKey: DEFAULT_MAIN_KEY,
107	    channel,
108	    accountId: params.accountId,
109	    peerKind: peer?.kind ?? "direct",
110	    peerId: peer ? normalizeId(peer.id) || "unknown" : null,
111	    dmScope: params.dmScope,
112	    identityLinks: params.identityLinks,
113	  });
114	}
