116	function listAgents(cfg: OpenClawConfig) {
117	  const agents = cfg.agents?.list;
118	  return Array.isArray(agents) ? agents : [];
119	}
120	
121	type AgentLookupCache = {
122	  agentsRef: OpenClawConfig["agents"] | undefined;
123	  byNormalizedId: Map<string, string>;
124	  fallbackDefaultAgentId: string;
125	};
126	
127	const agentLookupCacheByCfg = new WeakMap<OpenClawConfig, AgentLookupCache>();
128	
129	function resolveAgentLookupCache(cfg: OpenClawConfig): AgentLookupCache {
130	  const agentsRef = cfg.agents;
131	  const existing = agentLookupCacheByCfg.get(cfg);
132	  if (existing && existing.agentsRef === agentsRef) {
133	    return existing;
134	  }
135	
136	  const byNormalizedId = new Map<string, string>();
137	  for (const agent of listAgents(cfg)) {
138	    const rawId = agent.id?.trim();
139	    if (!rawId) {
140	      continue;
141	    }
142	    byNormalizedId.set(normalizeAgentId(rawId), sanitizeAgentId(rawId));
143	  }
144	  const next: AgentLookupCache = {
145	    agentsRef,
146	    byNormalizedId,
147	    fallbackDefaultAgentId: sanitizeAgentId(resolveDefaultAgentId(cfg)),
148	  };
149	  agentLookupCacheByCfg.set(cfg, next);
150	  return next;
151	}
152	
153	export function pickFirstExistingAgentId(cfg: OpenClawConfig, agentId: string): string {
154	  const lookup = resolveAgentLookupCache(cfg);
155	  const trimmed = (agentId ?? "").trim();
156	  if (!trimmed) {
157	    return lookup.fallbackDefaultAgentId;
158	  }
159	  const normalized = normalizeAgentId(trimmed);
160	  if (lookup.byNormalizedId.size === 0) {
161	    return sanitizeAgentId(trimmed);
162	  }
163	  const resolved = lookup.byNormalizedId.get(normalized);
164	  if (resolved) {
165	    return resolved;
166	  }
167	  return lookup.fallbackDefaultAgentId;
168	}
169	
170	type NormalizedPeerConstraint =
171	  | { state: "none" }
172	  | { state: "invalid" }
173	  | { state: "wildcard-kind"; kind: ChatType }
174	  | { state: "valid"; kind: ChatType; id: string };
175	
176	type NormalizedBindingMatch = {
177	  accountPattern: string;
178	  peer: NormalizedPeerConstraint;
179	  guildId: string | null;
180	  teamId: string | null;
181	  roles: string[] | null;
182	};
183	
184	type EvaluatedBinding = {
185	  binding: ReturnType<typeof listBindings>[number];
186	  match: NormalizedBindingMatch;
187	  order: number;
188	};
189	
190	type BindingScope = {
191	  peer: RoutePeer | null;
192	  guildId: string;
193	  teamId: string;
194	  memberRoleIds: Set<string>;
195	};
196	
197	type EvaluatedBindingsCache = {
198	  bindingsRef: OpenClawConfig["bindings"];
199	  byChannel: Map<string, EvaluatedBindingsByChannel>;
200	  byChannelAccount: Map<string, EvaluatedBinding[]>;
201	  byChannelAccountIndex: Map<string, EvaluatedBindingsIndex>;
202	};
203	
204	const evaluatedBindingsCacheByCfg = new WeakMap<OpenClawConfig, EvaluatedBindingsCache>();
205	const MAX_EVALUATED_BINDINGS_CACHE_KEYS = 2000;
206	const resolvedRouteCacheByCfg = new WeakMap<
207	  OpenClawConfig,
208	  {
209	    bindingsRef: OpenClawConfig["bindings"];
210	    agentsRef: OpenClawConfig["agents"];
211	    sessionRef: OpenClawConfig["session"];
212	    byKey: Map<string, ResolvedAgentRoute>;
213	  }
214	>();
215	const MAX_RESOLVED_ROUTE_CACHE_KEYS = 4000;
216	
217	type EvaluatedBindingsIndex = {
218	  byPeer: Map<string, EvaluatedBinding[]>;
219	  byPeerWildcard: EvaluatedBinding[];
220	  byGuildWithRoles: Map<string, EvaluatedBinding[]>;
221	  byGuild: Map<string, EvaluatedBinding[]>;
222	  byTeam: Map<string, EvaluatedBinding[]>;
223	  byAccount: EvaluatedBinding[];
224	  byChannel: EvaluatedBinding[];
225	};
226	
227	type EvaluatedBindingsByChannel = {
228	  byAccount: Map<string, EvaluatedBinding[]>;
229	  byAnyAccount: EvaluatedBinding[];
230	};
231	
232	function resolveAccountPatternKey(accountPattern: string): string {
233	  if (!accountPattern.trim()) {
234	    return DEFAULT_ACCOUNT_ID;
235	  }
236	  return normalizeAccountId(accountPattern);
237	}
238	
239	function buildEvaluatedBindingsByChannel(
240	  cfg: OpenClawConfig,
241	): Map<string, EvaluatedBindingsByChannel> {
242	  const byChannel = new Map<string, EvaluatedBindingsByChannel>();
243	  let order = 0;
244	  for (const binding of listBindings(cfg)) {
245	    if (!binding || typeof binding !== "object") {
246	      continue;
247	    }
248	    const channel = normalizeToken(binding.match?.channel);
249	    if (!channel) {
250	      continue;
251	    }
252	    const match = normalizeBindingMatch(binding.match);
253	    const evaluated: EvaluatedBinding = {
254	      binding,
255	      match,
256	      order,
257	    };
258	    order += 1;
259	    let bucket = byChannel.get(channel);
260	    if (!bucket) {
261	      bucket = {
262	        byAccount: new Map<string, EvaluatedBinding[]>(),
263	        byAnyAccount: [],
264	      };
265	      byChannel.set(channel, bucket);
266	    }
267	    if (match.accountPattern === "*") {
268	      bucket.byAnyAccount.push(evaluated);
269	      continue;
270	    }
271	    const accountKey = resolveAccountPatternKey(match.accountPattern);
272	    const existing = bucket.byAccount.get(accountKey);
273	    if (existing) {
274	      existing.push(evaluated);
275	      continue;
276	    }
277	    bucket.byAccount.set(accountKey, [evaluated]);
278	  }
279	  return byChannel;
280	}
281	
282	function mergeEvaluatedBindingsInSourceOrder(
283	  accountScoped: EvaluatedBinding[],
284	  anyAccount: EvaluatedBinding[],
285	): EvaluatedBinding[] {
286	  if (accountScoped.length === 0) {
287	    return anyAccount;
288	  }
289	  if (anyAccount.length === 0) {
290	    return accountScoped;
291	  }
292	  const merged: EvaluatedBinding[] = [];
293	  let accountIdx = 0;
294	  let anyIdx = 0;
295	  while (accountIdx < accountScoped.length && anyIdx < anyAccount.length) {
296	    const accountBinding = accountScoped[accountIdx];
297	    const anyBinding = anyAccount[anyIdx];
298	    if (
299	      (accountBinding?.order ?? Number.MAX_SAFE_INTEGER) <=
300	      (anyBinding?.order ?? Number.MAX_SAFE_INTEGER)
301	    ) {
302	      if (accountBinding) {
303	        merged.push(accountBinding);
304	      }
305	      accountIdx += 1;
306	      continue;
307	    }
308	    if (anyBinding) {
309	      merged.push(anyBinding);
310	    }
311	    anyIdx += 1;
312	  }
313	  if (accountIdx < accountScoped.length) {
314	    merged.push(...accountScoped.slice(accountIdx));
315	  }
316	  if (anyIdx < anyAccount.length) {
317	    merged.push(...anyAccount.slice(anyIdx));
318	  }
319	  return merged;
320	}
321	
322	function pushToIndexMap(
323	  map: Map<string, EvaluatedBinding[]>,
324	  key: string | null,
325	  binding: EvaluatedBinding,
326	): void {
327	  if (!key) {
328	    return;
329	  }
330	  const existing = map.get(key);
331	  if (existing) {
332	    existing.push(binding);
333	    return;
334	  }
335	  map.set(key, [binding]);
336	}
337	
338	function peerLookupKeys(kind: ChatType, id: string): string[] {
339	  if (kind === "group") {
340	    return [`group:${id}`, `channel:${id}`];
341	  }
342	  if (kind === "channel") {
343	    return [`channel:${id}`, `group:${id}`];
344	  }
345	  return [`${kind}:${id}`];
346	}
347	
348	function collectPeerIndexedBindings(
349	  index: EvaluatedBindingsIndex,
350	  peer: RoutePeer | null,
351	): EvaluatedBinding[] {
352	  if (!peer) {
353	    return [];
354	  }
355	  const out: EvaluatedBinding[] = [];
356	  const seen = new Set<EvaluatedBinding>();
357	  for (const key of peerLookupKeys(peer.kind, peer.id)) {
358	    const matches = index.byPeer.get(key);
359	    if (!matches) {
360	      continue;
361	    }
362	    for (const match of matches) {
363	      if (seen.has(match)) {
364	        continue;
365	      }
366	      seen.add(match);
367	      out.push(match);
368	    }
369	  }
370	  return out;
371	}
372	
373	function buildEvaluatedBindingsIndex(bindings: EvaluatedBinding[]): EvaluatedBindingsIndex {
374	  const byPeer = new Map<string, EvaluatedBinding[]>();
375	  const byPeerWildcard: EvaluatedBinding[] = [];
376	  const byGuildWithRoles = new Map<string, EvaluatedBinding[]>();
377	  const byGuild = new Map<string, EvaluatedBinding[]>();
378	  const byTeam = new Map<string, EvaluatedBinding[]>();
379	  const byAccount: EvaluatedBinding[] = [];
380	  const byChannel: EvaluatedBinding[] = [];
381	
382	  for (const binding of bindings) {
383	    if (binding.match.peer.state === "valid") {
384	      for (const key of peerLookupKeys(binding.match.peer.kind, binding.match.peer.id)) {
385	        pushToIndexMap(byPeer, key, binding);
386	      }
387	      continue;
388	    }
389	    if (binding.match.peer.state === "wildcard-kind") {
390	      byPeerWildcard.push(binding);
391	      continue;
392	    }
393	    if (binding.match.guildId && binding.match.roles) {
394	      pushToIndexMap(byGuildWithRoles, binding.match.guildId, binding);
395	      continue;
396	    }
397	    if (binding.match.guildId && !binding.match.roles) {
398	      pushToIndexMap(byGuild, binding.match.guildId, binding);
399	      continue;
400	    }
401	    if (binding.match.teamId) {
402	      pushToIndexMap(byTeam, binding.match.teamId, binding);
403	      continue;
404	    }
405	    if (binding.match.accountPattern !== "*") {
406	      byAccount.push(binding);
407	      continue;
408	    }
409	    byChannel.push(binding);
410	  }
411	
412	  return {
413	    byPeer,
414	    byPeerWildcard,
415	    byGuildWithRoles,
416	    byGuild,
417	    byTeam,
418	    byAccount,
419	    byChannel,
420	  };
421	}
422	
423	function getEvaluatedBindingsForChannelAccount(
424	  cfg: OpenClawConfig,
425	  channel: string,
426	  accountId: string,
427	): EvaluatedBinding[] {
428	  const bindingsRef = cfg.bindings;
429	  const existing = evaluatedBindingsCacheByCfg.get(cfg);
430	  const cache =
431	    existing && existing.bindingsRef === bindingsRef
432	      ? existing
433	      : {
434	          bindingsRef,
435	          byChannel: buildEvaluatedBindingsByChannel(cfg),
436	          byChannelAccount: new Map<string, EvaluatedBinding[]>(),
437	          byChannelAccountIndex: new Map<string, EvaluatedBindingsIndex>(),
438	        };
439	  if (cache !== existing) {
440	    evaluatedBindingsCacheByCfg.set(cfg, cache);
441	  }
442	
443	  const cacheKey = `${channel}\t${accountId}`;
444	  const hit = cache.byChannelAccount.get(cacheKey);
445	  if (hit) {
446	    return hit;
447	  }
448	
449	  const channelBindings = cache.byChannel.get(channel);
450	  const accountScoped = channelBindings?.byAccount.get(accountId) ?? [];
451	  const anyAccount = channelBindings?.byAnyAccount ?? [];
452	  const evaluated = mergeEvaluatedBindingsInSourceOrder(accountScoped, anyAccount);
453	
454	  cache.byChannelAccount.set(cacheKey, evaluated);
455	  cache.byChannelAccountIndex.set(cacheKey, buildEvaluatedBindingsIndex(evaluated));
456	  if (cache.byChannelAccount.size > MAX_EVALUATED_BINDINGS_CACHE_KEYS) {
457	    cache.byChannelAccount.clear();
458	    cache.byChannelAccountIndex.clear();
459	    cache.byChannelAccount.set(cacheKey, evaluated);
460	    cache.byChannelAccountIndex.set(cacheKey, buildEvaluatedBindingsIndex(evaluated));
461	  }
462	
463	  return evaluated;
464	}
465	
466	function getEvaluatedBindingIndexForChannelAccount(
467	  cfg: OpenClawConfig,
468	  channel: string,
469	  accountId: string,
470	): EvaluatedBindingsIndex {
471	  const bindings = getEvaluatedBindingsForChannelAccount(cfg, channel, accountId);
472	  const existing = evaluatedBindingsCacheByCfg.get(cfg);
473	  const cacheKey = `${channel}\t${accountId}`;
474	  const indexed = existing?.byChannelAccountIndex.get(cacheKey);
475	  if (indexed) {
476	    return indexed;
477	  }
478	  const built = buildEvaluatedBindingsIndex(bindings);
479	  existing?.byChannelAccountIndex.set(cacheKey, built);
480	  return built;
481	}
482	
483	function normalizePeerConstraint(
484	  peer: { kind?: string; id?: string } | undefined,
485	): NormalizedPeerConstraint {
486	  if (!peer) {
487	    return { state: "none" };
488	  }
489	  const kind = normalizeChatType(peer.kind);
490	  const id = normalizeId(peer.id);
491	  if (!kind || !id) {
492	    return { state: "invalid" };
493	  }
494	  if (id === "*") {
495	    return { state: "wildcard-kind", kind };
496	  }
497	  return { state: "valid", kind, id };
498	}
499	
500	function normalizeBindingMatch(
501	  match:
502	    | {
503	        accountId?: string | undefined;
504	        peer?: { kind?: string; id?: string } | undefined;
505	        guildId?: string | undefined;
506	        teamId?: string | undefined;
507	        roles?: string[] | undefined;
508	      }
509	    | undefined,
510	): NormalizedBindingMatch {
511	  const rawRoles = match?.roles;
512	  return {
513	    accountPattern: (match?.accountId ?? "").trim(),
514	    peer: normalizePeerConstraint(match?.peer),
515	    guildId: normalizeId(match?.guildId) || null,
516	    teamId: normalizeId(match?.teamId) || null,
517	    roles: Array.isArray(rawRoles) && rawRoles.length > 0 ? rawRoles : null,
518	  };
519	}
520	
521	function resolveRouteCacheForConfig(cfg: OpenClawConfig): Map<string, ResolvedAgentRoute> {
522	  const existing = resolvedRouteCacheByCfg.get(cfg);
523	  if (
524	    existing &&
525	    existing.bindingsRef === cfg.bindings &&
526	    existing.agentsRef === cfg.agents &&
527	    existing.sessionRef === cfg.session
528	  ) {
529	    return existing.byKey;
530	  }
531	  const byKey = new Map<string, ResolvedAgentRoute>();
532	  resolvedRouteCacheByCfg.set(cfg, {
533	    bindingsRef: cfg.bindings,
534	    agentsRef: cfg.agents,
535	    sessionRef: cfg.session,
536	    byKey,
537	  });
538	  return byKey;
539	}
540	
541	function formatRouteCachePeer(peer: RoutePeer | null): string {
542	  if (!peer || !peer.id) {
543	    return "-";
544	  }
545	  return `${peer.kind}:${peer.id}`;
546	}
547	
548	function formatRoleIdsCacheKey(roleIds: string[]): string {
549	  const count = roleIds.length;
550	  if (count === 0) {
551	    return "-";
552	  }
553	  if (count === 1) {
554	    return roleIds[0] ?? "-";
555	  }
556	  if (count === 2) {
557	    const first = roleIds[0] ?? "";
558	    const second = roleIds[1] ?? "";
559	    return first <= second ? `${first},${second}` : `${second},${first}`;
560	  }
561	  return roleIds.toSorted().join(",");
562	}
563	
564	function buildResolvedRouteCacheKey(params: {
565	  channel: string;
566	  accountId: string;
567	  peer: RoutePeer | null;
568	  parentPeer: RoutePeer | null;
569	  guildId: string;
570	  teamId: string;
571	  memberRoleIds: string[];
572	  dmScope: string;
573	}): string {
574	  return `${params.channel}\t${params.accountId}\t${formatRouteCachePeer(params.peer)}\t${formatRouteCachePeer(params.parentPeer)}\t${params.guildId || "-"}\t${params.teamId || "-"}\t${formatRoleIdsCacheKey(params.memberRoleIds)}\t${params.dmScope}`;
575	}
576	
577	function hasGuildConstraint(match: NormalizedBindingMatch): boolean {
578	  return Boolean(match.guildId);
579	}
580	
581	function hasTeamConstraint(match: NormalizedBindingMatch): boolean {
582	  return Boolean(match.teamId);
583	}
584	
585	function hasRolesConstraint(match: NormalizedBindingMatch): boolean {
586	  return Boolean(match.roles);
587	}
588	
589	function peerKindMatches(bindingKind: ChatType, scopeKind: ChatType): boolean {
590	  if (bindingKind === scopeKind) {
591	    return true;
592	  }
593	  const both = new Set([bindingKind, scopeKind]);
594	  return both.has("group") && both.has("channel");
595	}
596	
597	function matchesBindingScope(match: NormalizedBindingMatch, scope: BindingScope): boolean {
598	  if (match.peer.state === "invalid") {
599	    return false;
600	  }
601	  if (match.peer.state === "valid") {
602	    if (
603	      !scope.peer ||
604	      !peerKindMatches(match.peer.kind, scope.peer.kind) ||
605	      scope.peer.id !== match.peer.id
606	    ) {
607	      return false;
608	    }
609	  }
610	  if (match.peer.state === "wildcard-kind") {
611	    if (!scope.peer || !peerKindMatches(match.peer.kind, scope.peer.kind)) {
612	      return false;
613	    }
614	  }
615	  if (match.guildId && match.guildId !== scope.guildId) {
616	    return false;
617	  }
618	  if (match.teamId && match.teamId !== scope.teamId) {
619	    return false;
620	  }
621	  if (match.roles) {
622	    for (const role of match.roles) {
623	      if (scope.memberRoleIds.has(role)) {
624	        return true;
625	      }
626	    }
627	    return false;
628	  }
629	  return true;
630	}
