632	export function resolveAgentRoute(input: ResolveAgentRouteInput): ResolvedAgentRoute {
633	  const channel = normalizeToken(input.channel);
634	  const accountId = normalizeAccountId(input.accountId);
635	  const peer = input.peer
636	    ? {
637	        kind: normalizeChatType(input.peer.kind) ?? input.peer.kind,
638	        id: normalizeId(input.peer.id),
639	      }
640	    : null;
641	  const guildId = normalizeId(input.guildId);
642	  const teamId = normalizeId(input.teamId);
643	  const memberRoleIds = input.memberRoleIds ?? [];
644	  const memberRoleIdSet = new Set(memberRoleIds);
645	  const dmScope = input.cfg.session?.dmScope ?? "main";
646	  const identityLinks = input.cfg.session?.identityLinks;
647	  const shouldLogDebug = shouldLogVerbose();
648	  const parentPeer = input.parentPeer
649	    ? {
650	        kind: normalizeChatType(input.parentPeer.kind) ?? input.parentPeer.kind,
651	        id: normalizeId(input.parentPeer.id),
652	      }
653	    : null;
654	
655	  const routeCache =
656	    !shouldLogDebug && !identityLinks ? resolveRouteCacheForConfig(input.cfg) : null;
657	  const routeCacheKey = routeCache
658	    ? buildResolvedRouteCacheKey({
659	        channel,
660	        accountId,
661	        peer,
662	        parentPeer,
663	        guildId,
664	        teamId,
665	        memberRoleIds,
666	        dmScope,
667	      })
668	    : "";
669	  if (routeCache && routeCacheKey) {
670	    const cachedRoute = routeCache.get(routeCacheKey);
671	    if (cachedRoute) {
672	      return { ...cachedRoute };
673	    }
674	  }
675	
676	  const bindings = getEvaluatedBindingsForChannelAccount(input.cfg, channel, accountId);
677	  const bindingsIndex = getEvaluatedBindingIndexForChannelAccount(input.cfg, channel, accountId);
678	
679	  const choose = (agentId: string, matchedBy: ResolvedAgentRoute["matchedBy"]) => {
