61	async function resolveRequestedChannel(params: {
62	  requestChannel: unknown;
63	  unsupportedMessage: (input: string) => string;
64	  rejectWebchatAsInternalOnly?: boolean;
65	}): Promise<
66	  | {
67	      cfg: OpenClawConfig;
68	      channel: string;
69	    }
70	  | {
71	      error: ReturnType<typeof errorShape>;
72	    }
73	> {
74	  const channelInput = readStringValue(params.requestChannel);
75	  const normalizedChannel = channelInput ? normalizeChannelId(channelInput) : null;
76	  if (channelInput && !normalizedChannel) {
77	    const normalizedInput = normalizeOptionalLowercaseString(channelInput) ?? "";
78	    if (params.rejectWebchatAsInternalOnly && normalizedInput === "webchat") {
79	      return {
80	        error: errorShape(
81	          ErrorCodes.INVALID_REQUEST,
82	          "unsupported channel: webchat (internal-only). Use `chat.send` for WebChat UI messages or choose a deliverable channel.",
83	        ),
84	      };
85	    }
86	    return {
87	      error: errorShape(ErrorCodes.INVALID_REQUEST, params.unsupportedMessage(channelInput)),
88	    };
89	  }
90	  const cfg = applyPluginAutoEnable({
91	    config: loadConfig(),
92	    env: process.env,
93	  }).config;
94	  let channel = normalizedChannel;
95	  if (!channel) {
96	    try {
97	      channel = (await resolveMessageChannelSelection({ cfg })).channel;
98	    } catch (err) {
99	      return { error: errorShape(ErrorCodes.INVALID_REQUEST, String(err)) };
100	    }
101	  }
102	  return { cfg, channel };
103	}
