505	    if (!validatePollParams(p)) {
506	      respond(
507	        false,
508	        undefined,
509	        errorShape(
510	          ErrorCodes.INVALID_REQUEST,
511	          `invalid poll params: ${formatValidationErrors(validatePollParams.errors)}`,
512	        ),
513	      );
514	      return;
515	    }
516	    const request = p as {
517	      to: string;
518	      question: string;
519	      options: string[];
520	      maxSelections?: number;
521	      durationSeconds?: number;
522	      durationHours?: number;
523	      silent?: boolean;
524	      isAnonymous?: boolean;
525	      threadId?: string;
526	      channel?: string;
527	      accountId?: string;
528	      idempotencyKey: string;
529	    };
530	    const idem = request.idempotencyKey;
531	    const cached = context.dedupe.get(`poll:${idem}`);
532	    if (cached) {
533	      respond(cached.ok, cached.payload, cached.error, {
534	        cached: true,
535	      });
536	      return;
537	    }
538	    const to = request.to.trim();
539	    const resolvedChannel = await resolveRequestedChannel({
540	      requestChannel: request.channel,
541	      unsupportedMessage: (input) => `unsupported poll channel: ${input}`,
542	    });
543	    if ("error" in resolvedChannel) {
544	      respond(false, undefined, resolvedChannel.error);
545	      return;
546	    }
547	    const { cfg, channel } = resolvedChannel;
548	    const plugin = resolveOutboundChannelPlugin({ channel, cfg });
549	    const outbound = plugin?.outbound;
550	    if (
551	      typeof request.durationSeconds === "number" &&
552	      outbound?.supportsPollDurationSeconds !== true
553	    ) {
554	      respond(
555	        false,
556	        undefined,
557	        errorShape(
558	          ErrorCodes.INVALID_REQUEST,
559	          `durationSeconds is not supported for ${channel} polls`,
560	        ),
561	      );
562	      return;
563	    }
564	    if (typeof request.isAnonymous === "boolean" && outbound?.supportsAnonymousPolls !== true) {
565	      respond(
566	        false,
567	        undefined,
568	        errorShape(ErrorCodes.INVALID_REQUEST, `isAnonymous is not supported for ${channel} polls`),
569	      );
570	      return;
571	    }
572	    const poll = {
573	      question: request.question,
574	      options: request.options,
575	      maxSelections: request.maxSelections,
576	      durationSeconds: request.durationSeconds,
577	      durationHours: request.durationHours,
578	    };
579	    const threadId = normalizeOptionalString(request.threadId);
580	    const accountId = normalizeOptionalString(request.accountId);
581	    try {
582	      if (!outbound?.sendPoll) {
583	        respond(
584	          false,
585	          undefined,
586	          errorShape(ErrorCodes.INVALID_REQUEST, `unsupported poll channel: ${channel}`),
587	        );
588	        return;
589	      }
590	      const resolvedTarget = resolveGatewayOutboundTarget({
591	        channel: channel,
592	        to,
593	        cfg,
594	        accountId,
595	      });
596	      if (!resolvedTarget.ok) {
597	        respond(false, undefined, resolvedTarget.error);
598	        return;
599	      }
600	      const normalized = outbound.pollMaxOptions
601	        ? normalizePollInput(poll, { maxOptions: outbound.pollMaxOptions })
602	        : normalizePollInput(poll);
603	      const result = await outbound.sendPoll({
604	        cfg,
605	        to: resolvedTarget.to,
606	        poll: normalized,
607	        accountId,
608	        threadId,
609	        silent: request.silent,
610	        isAnonymous: request.isAnonymous,
611	        gatewayClientScopes: client?.connect?.scopes ?? [],
612	      });
613	      const payload = buildGatewayDeliveryPayload({ runId: idem, channel, result });
614	      cacheGatewayDedupeSuccess({
615	        context,
616	        dedupeKey: `poll:${idem}`,
617	        payload,
618	      });
619	      respond(true, payload, undefined, { channel });
620	    } catch (err) {
621	      const error = errorShape(ErrorCodes.UNAVAILABLE, String(err));
622	      cacheGatewayDedupeFailure({
623	        context,
624	        dedupeKey: `poll:${idem}`,
625	        error,
626	      });
627	      respond(false, undefined, error, {
628	        channel,
629	        error: formatForLog(err),
630	      });
631	    }
632	  },
633	};
