310	function normalizeEmptyPayloadForDelivery(payload: ReplyPayload): ReplyPayload | null {
311	  const text = typeof payload.text === "string" ? payload.text : "";
312	  if (!text.trim()) {
313	    if (!hasReplyPayloadContent({ ...payload, text })) {
