326	function normalizePayloadsForChannelDelivery(
327	  plan: readonly OutboundPayloadPlan[],
328	  handler: ChannelHandler,
329	): ReplyPayload[] {
330	  const normalizedPayloads: ReplyPayload[] = [];
331	  for (const payload of projectOutboundPayloadPlanForDelivery(plan)) {
332	    let sanitizedPayload = payload;
333	    if (handler.sanitizeText && sanitizedPayload.text) {
334	      if (!handler.shouldSkipPlainTextSanitization?.(sanitizedPayload)) {
335	        sanitizedPayload = {
336	          ...sanitizedPayload,
337	          text: handler.sanitizeText(sanitizedPayload),
338	        };
339	      }
340	    }
341	    const normalizedPayload = handler.normalizePayload
342	      ? handler.normalizePayload(sanitizedPayload)
343	      : sanitizedPayload;
344	    const normalized = normalizedPayload
345	      ? normalizeEmptyPayloadForDelivery(normalizedPayload)
346	      : null;
347	    if (normalized) {
348	      normalizedPayloads.push(normalized);
349	    }
350	  }
351	  return normalizedPayloads;
352	}
