358	function createMessageSentEmitter(params: {
359	  hookRunner: ReturnType<typeof getGlobalHookRunner>;
360	  channel: Exclude<OutboundChannel, "none">;
361	  to: string;
362	  accountId?: string;
363	  sessionKeyForInternalHooks?: string;
364	  mirrorIsGroup?: boolean;
365	  mirrorGroupId?: string;
366	}): { emitMessageSent: (event: MessageSentEvent) => void; hasMessageSentHooks: boolean } {
367	  const hasMessageSentHooks = params.hookRunner?.hasHooks("message_sent") ?? false;
368	  const canEmitInternalHook = Boolean(params.sessionKeyForInternalHooks);
369	  const emitMessageSent = (event: MessageSentEvent) => {
370	    if (!hasMessageSentHooks && !canEmitInternalHook) {
371	      return;
372	    }
373	    const canonical = buildCanonicalSentMessageHookContext({
374	      to: params.to,
375	      content: event.content,
376	      success: event.success,
377	      error: event.error,
378	      channelId: params.channel,
379	      accountId: params.accountId ?? undefined,
380	      conversationId: params.to,
381	      messageId: event.messageId,
382	      isGroup: params.mirrorIsGroup,
383	      groupId: params.mirrorGroupId,
384	    });
385	    if (hasMessageSentHooks) {
386	      fireAndForgetHook(
387	        params.hookRunner!.runMessageSent(
388	          toPluginMessageSentEvent(canonical),
389	          toPluginMessageContext(canonical),
390	        ),
391	        "deliverOutboundPayloads: message_sent plugin hook failed",
392	        (message) => {
393	          log.warn(message);
394	        },
395	      );
396	    }
397	    if (!canEmitInternalHook) {
398	      return;
399	    }
400	    fireAndForgetHook(
401	      triggerInternalHook(
402	        createInternalHookEvent(
403	          "message",
404	          "sent",
405	          params.sessionKeyForInternalHooks!,
406	          toInternalMessageSentContext(canonical),
407	        ),
408	      ),
409	      "deliverOutboundPayloads: message:sent internal hook failed",
410	      (message) => {
411	        log.warn(message);
412	      },
413	    );
414	  };
415	  return { emitMessageSent, hasMessageSentHooks };
416	}
