418	async function applyMessageSendingHook(params: {
419	  hookRunner: ReturnType<typeof getGlobalHookRunner>;
420	  enabled: boolean;
421	  payload: ReplyPayload;
422	  payloadSummary: NormalizedOutboundPayload;
423	  to: string;
424	  channel: Exclude<OutboundChannel, "none">;
425	  accountId?: string;
426	}): Promise<{
427	  cancelled: boolean;
428	  payload: ReplyPayload;
429	  payloadSummary: NormalizedOutboundPayload;
430	}> {
431	  if (!params.enabled) {
432	    return {
433	      cancelled: false,
434	      payload: params.payload,
435	      payloadSummary: params.payloadSummary,
436	    };
437	  }
438	  try {
439	    const sendingResult = await params.hookRunner!.runMessageSending(
440	      {
441	        to: params.to,
442	        content: params.payloadSummary.text,
443	        metadata: {
444	          channel: params.channel,
445	          accountId: params.accountId,
446	          mediaUrls: params.payloadSummary.mediaUrls,
447	        },
448	      },
449	      {
450	        channelId: params.channel,
451	        accountId: params.accountId ?? undefined,
452	      },
453	    );
454	    if (sendingResult?.cancel) {
455	      return {
456	        cancelled: true,
457	        payload: params.payload,
458	        payloadSummary: params.payloadSummary,
459	      };
460	    }
461	    if (sendingResult?.content == null) {
462	      return {
463	        cancelled: false,
464	        payload: params.payload,
465	        payloadSummary: params.payloadSummary,
466	      };
467	    }
468	    const payload = {
469	      ...params.payload,
470	      text: sendingResult.content,
471	    };
472	    return {
473	      cancelled: false,
474	      payload,
475	      payloadSummary: {
476	        ...params.payloadSummary,
477	        text: sendingResult.content,
478	      },
479	    };
480	  } catch {
481	    // Don't block delivery on hook failure.
482	    return {
483	      cancelled: false,
484	      payload: params.payload,
485	      payloadSummary: params.payloadSummary,
486	    };
487	  }
488	}
