490	export async function deliverOutboundPayloads(
491	  params: DeliverOutboundPayloadsParams,
492	): Promise<OutboundDeliveryResult[]> {
493	  const { channel, to, payloads } = params;
494	
495	  // Write-ahead delivery queue: persist before sending, remove after success.
496	  const queueId = params.skipQueue
497	    ? null
498	    : await enqueueDelivery({
499	        channel,
500	        to,
501	        accountId: params.accountId,
502	        payloads,
503	        threadId: params.threadId,
504	        replyToId: params.replyToId,
505	        bestEffort: params.bestEffort,
506	        gifPlayback: params.gifPlayback,
507	        forceDocument: params.forceDocument,
508	        silent: params.silent,
509	        mirror: params.mirror,
510	        session: params.session,
511	        gatewayClientScopes: params.gatewayClientScopes,
512	      }).catch(() => null); // Best-effort — don't block delivery if queue write fails.
513	
514	  // Wrap onError to detect partial failures under bestEffort mode.
515	  // When bestEffort is true, per-payload errors are caught and passed to onError
516	  // without throwing — so the outer try/catch never fires. We track whether any
517	  // payload failed so we can call failDelivery instead of ackDelivery.
518	  let hadPartialFailure = false;
519	  const wrappedParams = params.onError
520	    ? {
521	        ...params,
522	        onError: (err: unknown, payload: NormalizedOutboundPayload) => {
523	          hadPartialFailure = true;
524	          params.onError!(err, payload);
525	        },
526	      }
527	    : params;
528	
529	  try {
530	    const results = await deliverOutboundPayloadsCore(wrappedParams);
531	    if (queueId) {
532	      if (hadPartialFailure) {
533	        await failDelivery(queueId, "partial delivery failure (bestEffort)").catch(() => {});
534	      } else {
535	        await ackDelivery(queueId).catch(() => {}); // Best-effort cleanup.
536	      }
537	    }
538	    return results;
539	  } catch (err) {
540	    if (queueId) {
541	      if (isAbortError(err)) {
542	        await ackDelivery(queueId).catch(() => {});
543	      } else {
544	        await failDelivery(queueId, formatErrorMessage(err)).catch(() => {});
545	      }
546	    }
547	    throw err;
548	  }
549	}
