551	/** Core delivery logic (extracted for queue wrapper). */
552	async function deliverOutboundPayloadsCore(
553	  params: DeliverOutboundPayloadsCoreParams,
554	): Promise<OutboundDeliveryResult[]> {
555	  const { cfg, channel, to, payloads } = params;
556	  const outboundPayloadPlan = createOutboundPayloadPlan(payloads);
557	  const accountId = params.accountId;
558	  const deps = params.deps;
559	  const abortSignal = params.abortSignal;
560	  const mediaAccess = resolveAgentScopedOutboundMediaAccess({
561	    cfg,
562	    agentId: params.session?.agentId ?? params.mirror?.agentId,
563	    mediaSources: collectPayloadMediaSources(outboundPayloadPlan),
564	    sessionKey: params.session?.key,
565	    messageProvider: params.session?.key ? undefined : channel,
566	    accountId: params.session?.requesterAccountId ?? accountId,
567	    requesterSenderId: params.session?.requesterSenderId,
568	    requesterSenderName: params.session?.requesterSenderName,
569	    requesterSenderUsername: params.session?.requesterSenderUsername,
570	    requesterSenderE164: params.session?.requesterSenderE164,
571	  });
572	  const results: OutboundDeliveryResult[] = [];
573	  const handler = await createChannelHandler({
574	    cfg,
575	    channel,
576	    to,
577	    deps,
578	    accountId,
579	    replyToId: params.replyToId,
580	    threadId: params.threadId,
581	    identity: params.identity,
582	    gifPlayback: params.gifPlayback,
583	    forceDocument: params.forceDocument,
584	    silent: params.silent,
585	    mediaAccess,
586	    gatewayClientScopes: params.gatewayClientScopes,
587	  });
588	  const configuredTextLimit = handler.chunker
589	    ? resolveTextChunkLimit(cfg, channel, accountId, {
590	        fallbackLimit: handler.textChunkLimit,
591	      })
592	    : undefined;
593	  const textLimit = handler.resolveEffectiveTextChunkLimit
594	    ? handler.resolveEffectiveTextChunkLimit(configuredTextLimit)
595	    : configuredTextLimit;
596	  const chunkMode = handler.chunker ? resolveChunkMode(cfg, channel, accountId) : "length";
597	
598	  const sendTextChunks = async (
599	    text: string,
600	    overrides?: {
601	      replyToId?: string | null;
602	      threadId?: string | number | null;
603	      audioAsVoice?: boolean;
604	    },
605	  ) => {
606	    throwIfAborted(abortSignal);
607	    if (!handler.chunker || textLimit === undefined) {
608	      results.push(await handler.sendText(text, overrides));
609	      return;
610	    }
611	    if (chunkMode === "newline") {
612	      const mode = handler.chunkerMode ?? "text";
613	      const blockChunks =
614	        mode === "markdown"
615	          ? chunkMarkdownTextWithMode(text, textLimit, "newline")
616	          : chunkByParagraph(text, textLimit);
617	
618	      if (!blockChunks.length && text) {
619	        blockChunks.push(text);
620	      }
621	      for (const blockChunk of blockChunks) {
622	        const chunks = handler.chunker(blockChunk, textLimit);
623	        if (!chunks.length && blockChunk) {
624	          chunks.push(blockChunk);
625	        }
626	        for (const chunk of chunks) {
627	          throwIfAborted(abortSignal);
628	          results.push(await handler.sendText(chunk, overrides));
629	        }
630	      }
631	      return;
632	    }
633	    const chunks = handler.chunker(text, textLimit);
634	    for (const chunk of chunks) {
635	      throwIfAborted(abortSignal);
636	      results.push(await handler.sendText(chunk, overrides));
637	    }
638	  };
639	  const normalizedPayloads = normalizePayloadsForChannelDelivery(outboundPayloadPlan, handler);
640	  const hookRunner = getGlobalHookRunner();
641	  const sessionKeyForInternalHooks = params.mirror?.sessionKey ?? params.session?.key;
642	  const mirrorIsGroup = params.mirror?.isGroup;
643	  const mirrorGroupId = params.mirror?.groupId;
644	  const { emitMessageSent, hasMessageSentHooks } = createMessageSentEmitter({
645	    hookRunner,
646	    channel,
647	    to,
648	    accountId,
649	    sessionKeyForInternalHooks,
650	    mirrorIsGroup,
651	    mirrorGroupId,
652	  });
653	  const hasMessageSendingHooks = hookRunner?.hasHooks("message_sending") ?? false;
654	  if (hasMessageSentHooks && params.session?.agentId && !sessionKeyForInternalHooks) {
655	    log.warn(
656	      "deliverOutboundPayloads: session.agentId present without session key; internal message:sent hook will be skipped",
657	      {
658	        channel,
659	        to,
660	        agentId: params.session.agentId,
661	      },
662	    );
663	  }
664	  for (const payload of normalizedPayloads) {
665	    let payloadSummary = buildPayloadSummary(payload);
666	    try {
667	      throwIfAborted(abortSignal);
668	
669	      // Run message_sending plugin hook (may modify content or cancel)
670	      const hookResult = await applyMessageSendingHook({
671	        hookRunner,
672	        enabled: hasMessageSendingHooks,
673	        payload,
674	        payloadSummary,
675	        to,
676	        channel,
677	        accountId,
678	      });
679	      if (hookResult.cancelled) {
680	        continue;
681	      }
682	      const effectivePayload = hookResult.payload;
683	      payloadSummary = hookResult.payloadSummary;
684	
685	      params.onPayload?.(payloadSummary);
686	      const sendOverrides = {
687	        replyToId: effectivePayload.replyToId ?? params.replyToId ?? undefined,
688	        threadId: params.threadId ?? undefined,
689	        audioAsVoice: effectivePayload.audioAsVoice === true ? true : undefined,
690	        forceDocument: params.forceDocument,
691	      };
692	      if (
693	        handler.sendPayload &&
694	        hasReplyPayloadContent({
695	          interactive: effectivePayload.interactive,
696	          channelData: effectivePayload.channelData,
697	        })
698	      ) {
699	        const delivery = await handler.sendPayload(effectivePayload, sendOverrides);
700	        results.push(delivery);
701	        emitMessageSent({
702	          success: true,
703	          content: payloadSummary.text,
704	          messageId: delivery.messageId,
705	        });
706	        continue;
707	      }
708	      if (payloadSummary.mediaUrls.length === 0) {
709	        const beforeCount = results.length;
710	        if (handler.sendFormattedText) {
711	          results.push(...(await handler.sendFormattedText(payloadSummary.text, sendOverrides)));
712	        } else {
713	          await sendTextChunks(payloadSummary.text, sendOverrides);
714	        }
715	        const messageId = results.at(-1)?.messageId;
716	        emitMessageSent({
717	          success: results.length > beforeCount,
718	          content: payloadSummary.text,
719	          messageId,
720	        });
721	        continue;
722	      }
723	
724	      if (!handler.supportsMedia) {
725	        log.warn(
726	          "Plugin outbound adapter does not implement sendMedia; media URLs will be dropped and text fallback will be used",
727	          {
728	            channel,
729	            to,
730	            mediaCount: payloadSummary.mediaUrls.length,
731	          },
732	        );
733	        const fallbackText = payloadSummary.text.trim();
734	        if (!fallbackText) {
735	          throw new Error(
736	            "Plugin outbound adapter does not implement sendMedia and no text fallback is available for media payload",
737	          );
738	        }
739	        const beforeCount = results.length;
740	        await sendTextChunks(fallbackText, sendOverrides);
741	        const messageId = results.at(-1)?.messageId;
742	        emitMessageSent({
743	          success: results.length > beforeCount,
744	          content: payloadSummary.text,
745	          messageId,
746	        });
747	        continue;
748	      }
749	
750	      let lastMessageId: string | undefined;
751	      await sendMediaWithLeadingCaption({
752	        mediaUrls: payloadSummary.mediaUrls,
753	        caption: payloadSummary.text,
754	        send: async ({ mediaUrl, caption }) => {
755	          throwIfAborted(abortSignal);
756	          if (handler.sendFormattedMedia) {
757	            const delivery = await handler.sendFormattedMedia(
758	              caption ?? "",
759	              mediaUrl,
760	              sendOverrides,
761	            );
762	            results.push(delivery);
763	            lastMessageId = delivery.messageId;
764	            return;
765	          }
766	          const delivery = await handler.sendMedia(caption ?? "", mediaUrl, sendOverrides);
767	          results.push(delivery);
768	          lastMessageId = delivery.messageId;
769	        },
770	      });
771	      emitMessageSent({
772	        success: true,
773	        content: payloadSummary.text,
774	        messageId: lastMessageId,
775	      });
776	    } catch (err) {
777	      emitMessageSent({
778	        success: false,
779	        content: payloadSummary.text,
780	        error: formatErrorMessage(err),
781	      });
782	      if (!params.bestEffort) {
783	        throw err;
784	      }
785	      params.onError?.(err, payloadSummary);
786	    }
787	  }
788	  if (params.mirror && results.length > 0) {
789	    const mirrorText = resolveMirroredTranscriptText({
790	      text: params.mirror.text,
791	      mediaUrls: params.mirror.mediaUrls,
792	    });
793	    if (mirrorText) {
794	      const { appendAssistantMessageToSessionTranscript } = await loadTranscriptRuntime();
795	      await appendAssistantMessageToSessionTranscript({
796	        agentId: params.mirror.agentId,
797	        sessionKey: params.mirror.sessionKey,
798	        text: mirrorText,
799	        idempotencyKey: params.mirror.idempotencyKey,
800	      });
801	    }
802	  }
803	
804	  return results;
805	}
