15	export type OutboundSessionRoute = {
16	  sessionKey: string;
17	  baseSessionKey: string;
18	  peer: RoutePeer;
19	  chatType: "direct" | "group" | "channel";
20	  from: string;
21	  to: string;
22	  threadId?: string | number;
23	};
24	
25	export type ResolveOutboundSessionRouteParams = {
26	  cfg: OpenClawConfig;
27	  channel: ChannelId;
28	  agentId: string;
29	  accountId?: string | null;
30	  target: string;
31	  currentSessionKey?: string;
32	  resolvedTarget?: ResolvedMessagingTarget;
33	  replyToId?: string | null;
34	  threadId?: string | number | null;
35	};
36	
37	function resolveOutboundChannelPlugin(channel: ChannelId) {
38	  return getChannelPlugin(channel);
39	}
40	
41	function stripProviderPrefix(raw: string, channel: string): string {
42	  const trimmed = raw.trim();
43	  const lower = normalizeLowercaseStringOrEmpty(trimmed);
44	  const prefix = `${normalizeLowercaseStringOrEmpty(channel)}:`;
45	  if (lower.startsWith(prefix)) {
46	    return trimmed.slice(prefix.length).trim();
47	  }
48	  return trimmed;
49	}
50	
51	function stripKindPrefix(raw: string): string {
52	  return raw.replace(/^(user|channel|group|conversation|room|dm):/i, "").trim();
53	}
54	
55	function inferPeerKind(params: {
56	  channel: ChannelId;
57	  resolvedTarget?: ResolvedMessagingTarget;
58	}): ChatType {
59	  const resolvedKind = params.resolvedTarget?.kind;
60	  if (resolvedKind === "user") {
61	    return "direct";
62	  }
63	  if (resolvedKind === "channel") {
64	    return "channel";
65	  }
66	  if (resolvedKind === "group") {
67	    const plugin = resolveOutboundChannelPlugin(params.channel);
68	    const chatTypes = plugin?.capabilities?.chatTypes ?? [];
69	    const supportsChannel = chatTypes.includes("channel");
70	    const supportsGroup = chatTypes.includes("group");
71	    if (supportsChannel && !supportsGroup) {
72	      return "channel";
73	    }
74	    return "group";
75	  }
76	  return "direct";
77	}
78	
79	function buildBaseSessionKey(params: {
80	  cfg: OpenClawConfig;
81	  agentId: string;
82	  channel: ChannelId;
83	  accountId?: string | null;
84	  peer: RoutePeer;
85	}): string {
86	  return buildAgentSessionKey({
87	    agentId: params.agentId,
88	    channel: params.channel,
89	    accountId: params.accountId,
90	    peer: params.peer,
91	    dmScope: params.cfg.session?.dmScope ?? "main",
92	    identityLinks: params.cfg.session?.identityLinks,
93	  });
94	}
95	
96	function resolveFallbackSession(
97	  params: ResolveOutboundSessionRouteParams,
98	): OutboundSessionRoute | null {
99	  const trimmed = stripProviderPrefix(params.target, params.channel).trim();
100	  if (!trimmed) {
101	    return null;
102	  }
103	  const peerKind = inferPeerKind({
104	    channel: params.channel,
105	    resolvedTarget: params.resolvedTarget,
106	  });
107	  const peerId = stripKindPrefix(trimmed);
108	  if (!peerId) {
109	    return null;
110	  }
111	  const peer: RoutePeer = { kind: peerKind, id: peerId };
112	  const baseSessionKey = buildBaseSessionKey({
113	    cfg: params.cfg,
114	    agentId: params.agentId,
115	    channel: params.channel,
116	    accountId: params.accountId,
117	    peer,
118	  });
119	  const chatType = peerKind === "direct" ? "direct" : peerKind === "channel" ? "channel" : "group";
120	  const from =
121	    peerKind === "direct"
122	      ? `${params.channel}:${peerId}`
123	      : `${params.channel}:${peerKind}:${peerId}`;
124	  const toPrefix = peerKind === "direct" ? "user" : "channel";
125	  return {
126	    sessionKey: baseSessionKey,
127	    baseSessionKey,
128	    peer,
129	    chatType,
130	    from,
131	    to: `${toPrefix}:${peerId}`,
132	  };
133	}
134	
135	export async function resolveOutboundSessionRoute(
136	  params: ResolveOutboundSessionRouteParams,
137	): Promise<OutboundSessionRoute | null> {
138	  const target = params.target.trim();
139	  if (!target) {
140	    return null;
141	  }
142	  const nextParams = { ...params, target };
143	  const resolver = resolveOutboundChannelPlugin(params.channel)?.messaging
144	    ?.resolveOutboundSessionRoute;
145	  if (resolver) {
146	    return await resolver(nextParams);
147	  }
148	  return resolveFallbackSession(nextParams);
149	}
150	
151	export async function ensureOutboundSessionEntry(params: {
152	  cfg: OpenClawConfig;
153	  channel: ChannelId;
154	  accountId?: string | null;
155	  route: OutboundSessionRoute;
156	}): Promise<void> {
157	  const storePath = resolveStorePath(params.cfg.session?.store, {
158	    agentId: resolveAgentIdFromSessionKey(params.route.sessionKey),
159	  });
160	  const ctx: MsgContext = {
161	    From: params.route.from,
162	    To: params.route.to,
163	    SessionKey: params.route.sessionKey,
164	    AccountId: params.accountId ?? undefined,
165	    ChatType: params.route.chatType,
166	    Provider: params.channel,
167	    Surface: params.channel,
168	    MessageThreadId: params.route.threadId,
169	    OriginatingChannel: params.channel,
170	    OriginatingTo: params.route.to,
171	  };
172	  try {
173	    await recordSessionMetaFromInbound({
174	      storePath,
175	      sessionKey: params.route.sessionKey,
176	      ctx,
177	    });
178	  } catch {
179	    // Do not block outbound sends on session meta writes.
180	  }
181	}
