5	function requiresTrustedRequesterSender(ctx: ChannelMessageActionContext): boolean {
6	  const plugin = getChannelPlugin(ctx.channel);
7	  return Boolean(
8	    plugin?.actions?.requiresTrustedRequesterSender?.({
9	      action: ctx.action,
10	      toolContext: ctx.toolContext,
11	    }),
12	  );
13	}
