15	export async function dispatchChannelMessageAction(
16	  ctx: ChannelMessageActionContext,
17	): Promise<AgentToolResult<unknown> | null> {
18	  if (requiresTrustedRequesterSender(ctx) && !ctx.requesterSenderId?.trim()) {
19	    throw new Error(
20	      `Trusted sender identity is required for ${ctx.channel}:${ctx.action} in tool-driven contexts.`,
21	    );
22	  }
23	  const plugin = getChannelPlugin(ctx.channel);
24	  if (!plugin?.actions?.handleAction) {
25	    return null;
26	  }
27	  if (plugin.actions.supportsAction && !plugin.actions.supportsAction({ action: ctx.action })) {
28	    return null;
29	  }
30	  return await plugin.actions.handleAction(ctx);
31	}
