1	import type { ActiveChannelPluginRuntimeShape } from "../../plugins/channel-registry-state.types.js";
2	import {
3	  getActivePluginChannelRegistryFromState,
4	  getActivePluginChannelRegistryVersionFromState,
5	} from "../../plugins/runtime-channel-state.js";
6	import { normalizeOptionalString } from "../../shared/string-coerce.js";
7	import { CHAT_CHANNEL_ORDER } from "../registry.js";
8	
9	export type LoadedChannelPlugin = ActiveChannelPluginRuntimeShape & {
10	  id: string;
11	  meta: NonNullable<ActiveChannelPluginRuntimeShape["meta"]>;
12	};
13	
14	type CachedChannelPlugins = {
15	  registryVersion: number;
16	  registryRef: object | null;
17	  sorted: LoadedChannelPlugin[];
18	  byId: Map<string, LoadedChannelPlugin>;
19	};
20	
21	const EMPTY_CHANNEL_PLUGIN_CACHE: CachedChannelPlugins = {
22	  registryVersion: -1,
23	  registryRef: null,
24	  sorted: [],
25	  byId: new Map(),
26	};
27	
28	let cachedChannelPlugins = EMPTY_CHANNEL_PLUGIN_CACHE;
29	
30	function coerceLoadedChannelPlugin(
31	  plugin: ActiveChannelPluginRuntimeShape | null | undefined,
32	): LoadedChannelPlugin | null {
33	  const id = normalizeOptionalString(plugin?.id) ?? "";
34	  if (!plugin || !id) {
35	    return null;
36	  }
37	  if (!plugin.meta || typeof plugin.meta !== "object") {
38	    plugin.meta = {};
39	  }
40	  return plugin as LoadedChannelPlugin;
41	}
42	
43	function dedupeChannels(channels: LoadedChannelPlugin[]): LoadedChannelPlugin[] {
44	  const seen = new Set<string>();
45	  const resolved: LoadedChannelPlugin[] = [];
46	  for (const plugin of channels) {
47	    const id = normalizeOptionalString(plugin.id) ?? "";
48	    if (!id || seen.has(id)) {
49	      continue;
50	    }
51	    seen.add(id);
52	    resolved.push(plugin);
53	  }
54	  return resolved;
55	}
56	
57	function resolveCachedChannelPlugins(): CachedChannelPlugins {
58	  const registry = getActivePluginChannelRegistryFromState();
59	  const registryVersion = getActivePluginChannelRegistryVersionFromState();
60	  const cached = cachedChannelPlugins;
61	  if (cached.registryVersion === registryVersion && cached.registryRef === registry) {
62	    return cached;
63	  }
64	
65	  const channelPlugins: LoadedChannelPlugin[] = [];
66	  if (registry && Array.isArray(registry.channels)) {
67	    for (const entry of registry.channels) {
68	      const plugin = coerceLoadedChannelPlugin(entry?.plugin);
69	      if (plugin) {
70	        channelPlugins.push(plugin);
71	      }
72	    }
73	  }
74	
75	  const sorted = dedupeChannels(channelPlugins).toSorted((a, b) => {
76	    const indexA = CHAT_CHANNEL_ORDER.indexOf(a.id);
77	    const indexB = CHAT_CHANNEL_ORDER.indexOf(b.id);
78	    const orderA = a.meta.order ?? (indexA === -1 ? 999 : indexA);
79	    const orderB = b.meta.order ?? (indexB === -1 ? 999 : indexB);
80	    if (orderA !== orderB) {
81	      return orderA - orderB;
82	    }
83	    return a.id.localeCompare(b.id);
84	  });
85	  const byId = new Map<string, LoadedChannelPlugin>();
86	  for (const plugin of sorted) {
87	    byId.set(plugin.id, plugin);
88	  }
89	
90	  const next: CachedChannelPlugins = {
91	    registryVersion,
92	    registryRef: registry,
93	    sorted,
94	    byId,
95	  };
96	  cachedChannelPlugins = next;
97	  return next;
98	}
99	
100	export function listLoadedChannelPlugins(): LoadedChannelPlugin[] {
101	  return resolveCachedChannelPlugins().sorted.slice();
102	}
103	
104	export function getLoadedChannelPluginById(id: string): LoadedChannelPlugin | undefined {
105	  const resolvedId = normalizeOptionalString(id) ?? "";
106	  if (!resolvedId) {
107	    return undefined;
108	  }
109	  return resolveCachedChannelPlugins().byId.get(resolvedId);
110	}
